    std::uint64_t aOrbiterI = 0; std::uint64_t aOrbiterJ = 0; std::uint64_t aOrbiterK = 0;

    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseA(pNonce * 0x8D87F9CA60C30F17ULL + 0xB2C48A9BBEB4BC13ULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseB(pNonce * 0xEFB8FD9FC32B13A5ULL + 0xBD62B04732EB8258ULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseC(pNonce * 0xE4D3EB801ED38B25ULL + 0xCCAAE5A21DCFA978ULL);
    std::uint64_t aNonceWordD = TwistMix64::DiffuseC(pNonce * 0x9E0F27915217A9A9ULL + 0xCA06F52A587198A7ULL);
    std::uint64_t aNonceWordE = TwistMix64::DiffuseB(pNonce * 0xA45B17550F1B51C1ULL + 0x99CB5C0875C503FCULL);
    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0xCD517C46FBD54069ULL + 0xA896A5A37AEE54EDULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseB(pNonce * 0xD35B59FE0AEE69ADULL + 0xB91DFB3D64009872ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0xBD6A8931CC6B4D29ULL + 0xFB57B905FB2CD7C4ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0xFFD67636AC398E0BULL + 0x9323ADF234D12293ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0xA5972DA5EF11B797ULL + 0xD81CCA8680E94A5DULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseA(pNonce * 0x92AACCECB3FA97ADULL + 0xA68A683413938AC5ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseA(pNonce * 0x9DC1F3EFBA2E7B69ULL + 0xBA6716EB3735ECC7ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0x9584D3ACA7D49D99ULL + 0xE88F0DEA7B51CB35ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0xD7600716BD7764BDULL + 0x8E3C83BAFA1A0347ULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseA(pNonce * 0xC7CD46D01A9AC9F3ULL + 0xC3E37CA54AA80A34ULL);
    std::uint64_t aNonceWordP = TwistMix64::DiffuseC(pNonce * 0xB6427363740BEA3BULL + 0xA4615400B47420D8ULL);
